   350→// parseRequest parses a request into parsed queries grouped by datasource uid
   351→func (s *ServiceImpl) parseMetricRequest(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest, supportLocalTimeRange bool) (*parsedRequest, error) {
   352→	if len(reqDTO.Queries) == 0 {
   353→		return nil, ErrNoQueriesFound
   354→	}
   355→
   356→	req := &parsedRequest{
   357→		hasExpression: false,
   358→		parsedQueries: make(map[string][]parsedQuery),
   359→		dsTypes:       make(map[string]bool),
   360→	}
   361→
   362→	// Parse the queries and store them by datasource
   363→	datasourcesByUid := map[string]*datasources.DataSource{}
   364→	for _, query := range reqDTO.Queries {
   365→		ds, err := s.getDataSourceFromQuery(ctx, user, skipDSCache, query, datasourcesByUid)
   366→		if err != nil {
   367→			return nil, err
   368→		}
   369→		if ds == nil {
   370→			return nil, ErrInvalidDatasourceID
   371→		}
   372→
   373→		datasourcesByUid[ds.UID] = ds
   374→		if expr.NodeTypeFromDatasourceUID(ds.UID) != expr.TypeDatasourceNode {
   375→			req.hasExpression = true
   376→		} else {
   377→			req.dsTypes[ds.Type] = true
   378→		}
   379→
   380→		if _, ok := req.parsedQueries[ds.UID]; !ok {
   381→			req.parsedQueries[ds.UID] = []parsedQuery{}
   382→		}
   383→
   384→		var timeRange gtime.TimeRange
   385→		if supportLocalTimeRange {
   386→			from, to, err := getTimeRange(query, reqDTO.From, reqDTO.To)
   387→			if err != nil {
   388→				return nil, err
   389→			}
   390→			timeRange = gtime.NewTimeRange(from, to)
   391→		} else {
   392→			timeRange = gtime.NewTimeRange(reqDTO.From, reqDTO.To)
   393→		}
   394→
   395→		modelJSON, err := query.MarshalJSON()
   396→		if err != nil {
   397→			return nil, err
   398→		}
   399→
   400→		pq := parsedQuery{
   401→			datasource: ds,
   402→			query: backend.DataQuery{
   403→				TimeRange: backend.TimeRange{
   404→					From: timeRange.GetFromAsTimeUTC(),
   405→					To:   timeRange.GetToAsTimeUTC(),
   406→				},
   407→				RefID:         query.Get("refId").MustString("A"),
   408→				MaxDataPoints: query.Get("maxDataPoints").MustInt64(100),
   409→				Interval:      time.Duration(query.Get("intervalMs").MustInt64(1000)) * time.Millisecond,
   410→				QueryType:     query.Get("queryType").MustString(""),
   411→				JSON:          modelJSON,
   412→			},
   413→			rawQuery: query,
   414→		}
   415→		req.parsedQueries[ds.UID] = append(req.parsedQueries[ds.UID], pq)
   416→
   417→		s.log.Debug("Processed metrics query",
   418→			"ref_id", pq.query.RefID,
   419→			"from", timeRange.GetFromAsMsEpoch(),
   420→			"to", timeRange.GetToAsMsEpoch(),
   421→			"interval", pq.query.Interval.Milliseconds(),
   422→			"max_data_points", pq.query.MaxDataPoints,
   423→			"query", string(modelJSON))
   424→	}
   425→
   426→	return req, req.validateRequest(ctx)
   427→}
