   429→func (s *ServiceImpl) getDataSourceFromQuery(ctx context.Context, user identity.Requester, skipDSCache bool, query *simplejson.Json, history map[string]*datasources.DataSource) (*datasources.DataSource, error) {
   430→	var err error
   431→	uid := query.Get("datasource").Get("uid").MustString()
   432→
   433→	// before 8.3 special types could be sent as datasource (expr)
   434→	if uid == "" {
   435→		uid = query.Get("datasource").MustString()
   436→	}
   437→
   438→	// check cache value
   439→	ds, ok := history[uid]
   440→	if ok {
   441→		return ds, nil
   442→	}
   443→
   444→	if kind := expr.NodeTypeFromDatasourceUID(uid); kind != expr.TypeDatasourceNode {
   445→		return expr.DataSourceModelFromNodeType(kind)
   446→	}
   447→
   448→	if uid == grafanads.DatasourceUID {
   449→		return grafanads.DataSourceModel(user.GetOrgID()), nil
   450→	}
   451→
   452→	if uid != "" {
   453→		ds, err = s.dataSourceCache.GetDatasourceByUID(ctx, uid, user, skipDSCache)
   454→		if err != nil {
   455→			return nil, err
   456→		}
   457→		return ds, nil
   458→	}
   459→
   460→	// use datasourceId if it exists
   461→	id := query.Get("datasourceId").MustInt64(0)
   462→	if id > 0 {
   463→		ds, err = s.dataSourceCache.GetDatasource(ctx, id, user, skipDSCache)
   464→		if err != nil {
   465→			return nil, err
   466→		}
   467→		return ds, nil
   468→	}
   469→
   470→	return nil, ErrInvalidDatasourceID
   471→}
